import pickle


class Payload(object):
    def __reduce__(self):
        return exec, ('import os;os.system("ls")',)


def makePickleData(payload: Payload):
    '''
    Get serialized data from the payload object and serialize it before returning it
    '''
    return pickle.dumps(payload)

from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml')
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    try:
        # Retrieve raw data from the request body
        yaml_data = request.get_data()
        if not yaml_data:
            return jsonify({"error": "No data provided"}), 400

        # Use safe_load to prevent arbitrary code execution (CWE-502)
        # yaml.load() is unsafe; yaml.safe_load() only loads standard YAML types
        parsed_data = yaml.safe_load(yaml_data)

        # Ensure the result is a type that can be serialized to JSON
        if parsed_data is None:
            return jsonify({"message": "Empty YAML document"}), 200

        return jsonify(parsed_data)
    except yaml.YAMLError as e:
        return jsonify({"error": f"Invalid YAML syntax: {str(e)}"}), 400
    except Exception as e:
        return jsonify({"error": "An internal server error occurred"}), 500
